                <Navbar/>
                <Routes>

                    <Route path="/" element={<Index />} />
                    <Route path="/Productos" element={<Productos/>} />
                    <Route path="/Ingresar" element={<Ingresar />} />
                </Routes>
                <Footer/>

            </BrowserRouter>
    )
}
